(function(){
  const blockDefinitions = new Map();
  let activeDrag = null;
  let blockId = 1;

  function uid() {
    blockId += 1;
    return `block-${blockId}`;
  }

  function deepClone(obj) {
    return JSON.parse(JSON.stringify(obj));
  }

  function parseLabel(definition, block) {
    if (definition.type === 'maze_repeat') {
      return { mode: 'repeat', before: 'повторить', after: 'раз' };
    }
    return { mode: 'text', text: definition.message0 || definition.type };
  }

  class BlocklyBlock {
    constructor(workspace, type, options = {}) {
      this.workspace = workspace;
      this.type = type;
      this.definition = blockDefinitions.get(type) || { type, message0: type };
      this.id = uid();
      this.next = null;
      this.parentList = null;
      this.childLists = {};
      this.fields = {};
      this.locked = Boolean(options.locked);
      this.position = { x: 0, y: 0 };
      this.dom = null;
      this.selected = false;
      this.initializeFields();
    }

    initializeFields() {
      const args = this.definition.args0 || [];
      args.forEach((arg) => {
        if (arg.type === 'field_number') {
          this.fields[arg.name] = arg.value ?? 0;
        }
        if (arg.type === 'input_statement') {
          this.childLists[arg.name] = [];
        }
      });
    }

    initSvg() {}
    render() {
      this.workspace.render();
    }
    moveBy(x, y) {
      this.position = { x, y };
      this.workspace.render();
    }
    select() {
      this.workspace.selectedBlockId = this.id;
      this.workspace.render();
    }
    getNextBlock() {
      return this.next;
    }
    getInputTargetBlock(name) {
      const list = this.childLists[name] || [];
      return list[0] || null;
    }
    getFieldValue(name) {
      return this.fields[name];
    }
  }

  class Workspace {
    constructor(container, options) {
      this.container = container;
      this.options = options || {};
      this.toolbox = options.toolbox || { contents: [] };
      this.selectedBlockId = null;
      this.rootBlocks = [];
      this.blockMap = new Map();
      this.startBlock = null;
      this.dom = {};
      this.setupDom();
      this.render();
    }

    setupDom() {
      this.container.innerHTML = '';
      const shell = document.createElement('div');
      shell.className = 'blockly-shell injectionDiv';

      const toolbox = document.createElement('aside');
      toolbox.className = 'blockly-toolbox';
      toolbox.innerHTML = '<h3>Блоки</h3>';
      const toolboxList = document.createElement('div');
      toolboxList.className = 'blockly-toolbox-list';
      toolbox.appendChild(toolboxList);

      const canvas = document.createElement('section');
      canvas.className = 'blockly-canvas';
      const dropzone = document.createElement('div');
      dropzone.className = 'blockly-dropzone';
      const stack = document.createElement('div');
      stack.className = 'blockly-stack blockly-root-stack';
      dropzone.appendChild(stack);
      canvas.appendChild(dropzone);

      shell.appendChild(toolbox);
      shell.appendChild(canvas);
      this.container.appendChild(shell);

      this.dom = { shell, toolbox, toolboxList, canvas, dropzone, stack };
      this.installDnD();
    }

    installDnD() {
      const allZones = () => Array.from(this.container.querySelectorAll('.blockly-stack, .blockly-input-stack, .blockly-dropzone'));
      this.container.addEventListener('dragstart', (event) => {
        const el = event.target.closest('.blockly-block');
        if (!el) return;
        const source = el.dataset.source;
        const blockId = el.dataset.blockId;
        activeDrag = { source, blockId, type: el.dataset.type };
        event.dataTransfer.effectAllowed = 'move';
        event.dataTransfer.setData('text/plain', blockId || el.dataset.type || 'block');
      });
      this.container.addEventListener('dragend', () => {
        allZones().forEach((zone) => zone.classList.remove('is-hover'));
        activeDrag = null;
      });
      this.container.addEventListener('dragover', (event) => {
        const zone = event.target.closest('.blockly-stack, .blockly-input-stack, .blockly-dropzone');
        if (!zone || !activeDrag) return;
        event.preventDefault();
        allZones().forEach((item) => item.classList.toggle('is-hover', item === zone));
      });
      this.container.addEventListener('drop', (event) => {
        const zone = event.target.closest('.blockly-stack, .blockly-input-stack, .blockly-dropzone');
        if (!zone || !activeDrag) return;
        event.preventDefault();
        allZones().forEach((item) => item.classList.remove('is-hover'));
        this.handleDrop(zone, activeDrag);
        activeDrag = null;
      });
      this.container.addEventListener('click', (event) => {
        const deleteButton = event.target.closest('.blockly-delete');
        if (deleteButton) {
          this.removeBlock(deleteButton.dataset.blockId);
          return;
        }
        const block = event.target.closest('.blockly-block[data-block-id]');
        if (!block) return;
        this.selectedBlockId = block.dataset.blockId;
        this.render();
      });
      this.container.addEventListener('change', (event) => {
        const input = event.target.closest('.blockly-field-number');
        if (!input) return;
        const block = this.blockMap.get(input.dataset.blockId);
        if (!block) return;
        block.fields[input.dataset.fieldName] = Math.max(1, Number.parseInt(input.value, 10) || 1);
        input.value = String(block.fields[input.dataset.fieldName]);
      });
    }

    handleDrop(zone, drag) {
      let block;
      if (drag.source === 'toolbox') {
        block = this.newBlock(drag.type);
      } else {
        block = this.blockMap.get(drag.blockId);
        this.detachBlock(block);
      }

      if (!block) return;
      const list = this.resolveList(zone);
      if (!list) return;
      block.parentList = list;
      list.push(block);
      this.relink(list);
      this.render();
    }

    resolveList(zone) {
      if (zone.classList.contains('blockly-root-stack') || zone.classList.contains('blockly-dropzone')) {
        return this.rootBlocks;
      }
      const ownerId = zone.dataset.ownerId;
      const inputName = zone.dataset.inputName;
      const block = this.blockMap.get(ownerId);
      if (!block) return null;
      if (!block.childLists[inputName]) block.childLists[inputName] = [];
      return block.childLists[inputName];
    }

    detachBlock(block) {
      if (!block || !block.parentList) return;
      const list = block.parentList;
      const index = list.findIndex((item) => item.id === block.id);
      if (index >= 0) list.splice(index, 1);
      this.relink(list);
      block.parentList = null;
    }

    removeBlock(blockId) {
      const block = this.blockMap.get(blockId);
      if (!block || block.locked) return;
      this.detachBlock(block);
      this.deleteRecursive(block);
      this.render();
    }

    deleteRecursive(block) {
      Object.values(block.childLists).forEach((list) => list.forEach((child) => this.deleteRecursive(child)));
      this.blockMap.delete(block.id);
      if (this.startBlock?.id === block.id) this.startBlock = null;
    }

    relink(list) {
      list.forEach((block, index) => {
        block.parentList = list;
        block.next = list[index + 1] || null;
      });
    }

    clear() {
      this.rootBlocks = [];
      this.blockMap.clear();
      this.startBlock = null;
      this.render();
    }

    newBlock(type) {
      const block = new BlocklyBlock(this, type, { locked: type === 'maze_start' });
      this.blockMap.set(block.id, block);
      if (type === 'maze_start') {
        this.startBlock = block;
        if (!this.rootBlocks.includes(block)) {
          this.rootBlocks.unshift(block);
          block.parentList = this.rootBlocks;
          this.relink(this.rootBlocks);
        }
      }
      return block;
    }

    centerOnBlock() {}
    scrollCenter() {}

    updateToolbox(toolbox) {
      this.toolbox = toolbox;
      this.render();
    }

    getBlocksByType(type) {
      const result = [];
      const visit = (list) => {
        list.forEach((block) => {
          if (block.type === type) result.push(block);
          Object.values(block.childLists).forEach((childList) => visit(childList));
        });
      };
      visit(this.rootBlocks);
      return result;
    }

    renderToolbox() {
      this.dom.toolboxList.innerHTML = '';
      (this.toolbox.contents || []).forEach((item) => {
        const def = blockDefinitions.get(item.type) || { type: item.type, message0: item.type };
        const preview = this.renderBlockDom(new BlocklyBlock(this, item.type), { source: 'toolbox', preview: true });
        preview.dataset.type = item.type;
        preview.dataset.source = 'toolbox';
        this.dom.toolboxList.appendChild(preview);
      });
    }

    render() {
      this.renderToolbox();
      this.dom.stack.innerHTML = '';
      this.renderList(this.rootBlocks, this.dom.stack, { root: true });
    }

    renderList(list, container, options = {}) {
      this.relink(list);
      if (!list.length && !options.root) {
        const empty = document.createElement('div');
        empty.className = 'blockly-empty';
        empty.textContent = 'Перетащите блок сюда';
        container.appendChild(empty);
      }
      list.forEach((block) => {
        container.appendChild(this.renderBlockDom(block, { source: 'workspace' }));
      });
    }

    renderBlockDom(block, { source, preview = false }) {
      const def = block.definition;
      const root = document.createElement('div');
      root.className = 'blockly-block';
      root.draggable = !block.locked;
      root.dataset.type = block.type;
      root.dataset.source = source;
      if (!preview) root.dataset.blockId = block.id;
      if (block.locked) root.dataset.locked = 'true';
      if (!preview && this.selectedBlockId === block.id) {
        root.style.outline = '3px solid rgba(255,255,255,.65)';
      }

      const header = document.createElement('div');
      header.className = 'blockly-block-header';
      const labelWrap = document.createElement('div');
      labelWrap.className = 'blockly-block-label';
      const parsed = parseLabel(def, block);
      if (parsed.mode === 'repeat') {
        const before = document.createElement('span');
        before.textContent = parsed.before;
        const input = document.createElement('input');
        input.className = 'blockly-field-number';
        input.type = 'number';
        input.min = '1';
        input.step = '1';
        input.value = String(block.fields.TIMES ?? 2);
        if (!preview) {
          input.dataset.blockId = block.id;
          input.dataset.fieldName = 'TIMES';
        } else {
          input.disabled = true;
        }
        const after = document.createElement('span');
        after.textContent = parsed.after;
        labelWrap.append(before, input, after);
      } else {
        labelWrap.textContent = parsed.text;
      }
      header.appendChild(labelWrap);
      const deleteButton = document.createElement('button');
      deleteButton.className = 'blockly-delete';
      deleteButton.type = 'button';
      deleteButton.textContent = '✕';
      if (!preview) deleteButton.dataset.blockId = block.id;
      header.appendChild(deleteButton);
      root.appendChild(header);

      Object.keys(block.childLists).forEach((inputName) => {
        const wrap = document.createElement('div');
        wrap.className = 'blockly-substack';
        const title = document.createElement('div');
        title.className = 'blockly-substack-title';
        title.textContent = 'Тело цикла';
        const inputStack = document.createElement('div');
        inputStack.className = 'blockly-input-stack';
        inputStack.dataset.ownerId = block.id;
        inputStack.dataset.inputName = inputName;
        this.renderList(block.childLists[inputName], inputStack, {});
        wrap.append(title, inputStack);
        root.appendChild(wrap);
      });

      return root;
    }
  }

  const Blockly = {
    common: {
      defineBlocksWithJsonArray(defs) {
        defs.forEach((def) => blockDefinitions.set(def.type, def));
      },
    },
    defineBlocksWithJsonArray(defs) {
      defs.forEach((def) => blockDefinitions.set(def.type, def));
    },
    inject(container, options) {
      return new Workspace(container, options);
    },
    svgResize() {},
  };

  window.Blockly = Blockly;
})();
